export default function DeadlinesBoard() {
  const [clients, setClients] = React.useState([]);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    tools.host_listDeadlines({}).then((r) => {
      setClients(r.data || []);
      setLoading(false);
    });
  }, []);

  const NOW = new Date("2026-07-21");
  const endOfWeek = new Date(NOW);
  endOfWeek.setDate(NOW.getDate() + (7 - NOW.getDay()));
  const endOfMonth = new Date(NOW.getFullYear(), NOW.getMonth() + 1, 0);

  function bucket(client) {
    const d = new Date(client.filingDeadline || client.deadline || "");
    if (isNaN(d)) return "later";
    if (d <= endOfWeek) return "week";
    if (d <= endOfMonth) return "month";
    return "later";
  }

  function daysAway(dateStr) {
    const d = new Date(dateStr);
    if (isNaN(d)) return null;
    return Math.round((d - NOW) / 86400000);
  }

  function deadlineLabel(dateStr) {
    const days = daysAway(dateStr);
    if (days === null) return "—";
    if (days < 0) return `${Math.abs(days)}d overdue`;
    if (days === 0) return "Today";
    if (days === 1) return "Tomorrow";
    return `${days} days away`;
  }

  function deadlineTone(dateStr) {
    const days = daysAway(dateStr);
    if (days === null) return "neutral";
    if (days <= 0) return "overdue";
    if (days <= 7) return "missing";
    if (days <= 31) return "review";
    return "neutral";
  }

  const week = clients.filter(c => bucket(c) === "week");
  const month = clients.filter(c => bucket(c) === "month");
  const later = clients.filter(c => bucket(c) === "later");

  const cardStyle = {
    background: "var(--vendo-color-surface)",
    border: "1px solid var(--vendo-color-border)",
    borderRadius: "var(--vendo-radius-medium)",
    padding: "14px 16px",
    display: "flex",
    flexDirection: "column",
    gap: 10,
    fontFamily: "var(--vendo-font-family)",
  };

  const sectionHeaderStyle = (tone) => ({
    fontFamily: "var(--vendo-font-family)",
    fontSize: 13,
    fontWeight: 600,
    letterSpacing: "0.04em",
    textTransform: "uppercase",
    color: tone === "danger" ? "var(--vendo-color-danger)" : tone === "warning" ? "#b45309" : "var(--vendo-color-muted)",
    marginBottom: 4,
  });

  const emptyStyle = {
    fontFamily: "var(--vendo-font-family)",
    fontSize: 14,
    color: "var(--vendo-color-muted)",
    padding: "12px 0",
  };

  function progressPct(client) {
    const received = client.documentsReceived ?? client.docsReceived ?? 0;
    const total = client.documentsTotal ?? client.docsTotal ?? 0;
    if (!total) return null;
    return { received, total, pct: Math.round((received / total) * 100) };
  }

  function missingKinds(client) {
    const kinds = client.missingDocumentKinds || client.missingKinds || [];
    return kinds.slice(0, 3).join(", ") + (kinds.length > 3 ? ` +${kinds.length - 3} more` : "");
  }

  function ClientCard({ client }) {
    const prog = progressPct(client);
    const dl = client.filingDeadline || client.deadline || "";
    const days = daysAway(dl);
    const tone = deadlineTone(dl);
    const badgeColors = {
      overdue: { bg: "#fef2f2", color: "var(--vendo-color-danger)", border: "#fecaca" },
      missing: { bg: "#fff7ed", color: "#b45309", border: "#fed7aa" },
      review:  { bg: "#fffbeb", color: "#92400e", border: "#fde68a" },
      neutral: { bg: "var(--vendo-color-background)", color: "var(--vendo-color-muted)", border: "var(--vendo-color-border)" },
    };
    const bc = badgeColors[tone] || badgeColors.neutral;

    return (
      <div style={cardStyle}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 8 }}>
          <div>
            <div style={{ fontFamily: "var(--vendo-font-family)", fontWeight: 600, fontSize: 15, color: "var(--vendo-color-text)" }}>
              {client.name || client.clientName || "—"}
            </div>
            {client.entityType && (
              <div style={{ fontFamily: "var(--vendo-font-family)", fontSize: 12, color: "var(--vendo-color-muted)", marginTop: 2 }}>
                {client.entityType}
              </div>
            )}
          </div>
          <span style={{
            fontSize: 12, fontWeight: 600, padding: "3px 9px", borderRadius: 99,
            background: bc.bg, color: bc.color, border: `1px solid ${bc.border}`,
            whiteSpace: "nowrap", fontFamily: "var(--vendo-font-family)",
          }}>
            {deadlineLabel(dl)}
          </span>
        </div>

        {dl && (
          <div style={{ fontFamily: "var(--vendo-font-family)", fontSize: 13, color: "var(--vendo-color-muted)" }}>
            Filing deadline: <span style={{ color: "var(--vendo-color-text)", fontWeight: 500 }}>
              {new Date(dl).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
            </span>
          </div>
        )}

        {prog !== null && (
          <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
            <div style={{ display: "flex", justifyContent: "space-between", fontFamily: "var(--vendo-font-family)", fontSize: 12, color: "var(--vendo-color-muted)" }}>
              <span>Documents collected</span>
              <span style={{ fontWeight: 600, color: "var(--vendo-color-text)" }}>{prog.received} of {prog.total}</span>
            </div>
            <div style={{ background: "var(--vendo-color-border)", borderRadius: 99, height: 6, overflow: "hidden" }}>
              <div style={{
                height: "100%",
                width: `${prog.pct}%`,
                background: prog.pct === 100 ? "#16a34a" : days !== null && days <= 7 ? "var(--vendo-color-danger)" : "var(--vendo-color-accent)",
                borderRadius: 99,
                transition: "width 0.4s ease",
              }}/>
            </div>
          </div>
        )}

        {client.assignedStaff && (
          <div style={{ fontFamily: "var(--vendo-font-family)", fontSize: 12, color: "var(--vendo-color-muted)" }}>
            Assigned: <span style={{ color: "var(--vendo-color-text)" }}>{client.assignedStaff}</span>
          </div>
        )}

        {missingKinds(client) && (
          <div style={{ fontFamily: "var(--vendo-font-family)", fontSize: 12, color: "var(--vendo-color-muted)" }}>
            Missing: <span style={{ color: "var(--vendo-color-danger)", fontWeight: 500 }}>{missingKinds(client)}</span>
          </div>
        )}
      </div>
    );
  }

  function Section({ title, clients, tone, emptyMsg }) {
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <span style={sectionHeaderStyle(tone)}>{title}</span>
          <span style={{
            fontSize: 12, fontWeight: 600, padding: "2px 8px", borderRadius: 99,
            background: tone === "danger" ? "#fef2f2" : tone === "warning" ? "#fff7ed" : "var(--vendo-color-background)",
            color: tone === "danger" ? "var(--vendo-color-danger)" : tone === "warning" ? "#b45309" : "var(--vendo-color-muted)",
            border: `1px solid ${tone === "danger" ? "#fecaca" : tone === "warning" ? "#fed7aa" : "var(--vendo-color-border)"}`,
            fontFamily: "var(--vendo-font-family)",
          }}>{clients.length}</span>
        </div>
        {clients.length === 0
          ? <div style={emptyStyle}>{emptyMsg}</div>
          : <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 12 }}>
              {clients.map((c, i) => <ClientCard key={c.id || i} client={c}/>)}
            </div>
        }
      </div>
    );
  }

  if (loading) {
    return (
      <div style={{ fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-muted)", padding: 24 }}>
        Loading deadlines…
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 28, padding: "4px 0" }}>
      <Section title="Due this week" clients={week} tone="danger" emptyMsg="No filing deadlines this week — nothing urgent."/>
      <div style={{ borderTop: "1px solid var(--vendo-color-border)" }}/>
      <Section title="Due this month" clients={month} tone="warning" emptyMsg="No filing deadlines remaining this month."/>
      <div style={{ borderTop: "1px solid var(--vendo-color-border)" }}/>
      <Section title="Later" clients={later} tone="neutral" emptyMsg="No upcoming deadlines beyond this month."/>
    </div>
  );
}
